import{_ as r,o as a,c as e,a2 as o}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"订阅链接使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/subscription.md","filePath":"guide/subscription.md","lastUpdated":1783292109000}'),s={name:"guide/subscription.md"};function n(i,t,l,d,h,c){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="订阅链接使用说明" tabindex="-1">订阅链接使用说明 <a class="header-anchor" href="#订阅链接使用说明" aria-label="Permalink to &quot;订阅链接使用说明&quot;">​</a></h1><p>订阅链接是你账号的&quot;节点通行证&quot;：客户端通过它自动拉取节点列表和分流配置。<strong>一条链接，所有设备通用</strong>（受套餐设备数限制）。</p><h2 id="在哪里获取" tabindex="-1">在哪里获取 <a class="header-anchor" href="#在哪里获取" aria-label="Permalink to &quot;在哪里获取&quot;">​</a></h2><p>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">会员中心</a>，<strong>订阅链接</strong> 卡片提供三种方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>复制链接</strong></td><td>粘贴到任意客户端的&quot;URL 导入 / 订阅&quot;入口</td></tr><tr><td><strong>扫描二维码</strong></td><td>手机客户端（Shadowrocket / Clash 系）扫码直接导入</td></tr><tr><td><strong>一键导入</strong></td><td>点客户端图标，自动唤起本机已安装的客户端完成导入</td></tr></tbody></table><h2 id="更新订阅" tabindex="-1">更新订阅 <a class="header-anchor" href="#更新订阅" aria-label="Permalink to &quot;更新订阅&quot;">​</a></h2><p>节点有增减（例如新地区上线）时，<strong>在客户端里手动更新一次订阅</strong>即可获取最新节点：</p><ul><li>Clash 系：配置页 → 更新（刷新图标）</li><li>Shadowrocket：首页订阅条目左滑 → 更新</li><li>v2rayN / v2rayNG：订阅分组 → 更新订阅</li></ul><p>建议每隔一段时间或看到节点上新公告后更新一次。</p><h2 id="重置订阅" tabindex="-1">重置订阅 <a class="header-anchor" href="#重置订阅" aria-label="Permalink to &quot;重置订阅&quot;">​</a></h2><p>如果怀疑订阅链接泄露（例如发在了公开场合），立即到 <strong>会员中心 → 账号设置 → 订阅中心</strong> 点击 <strong>重置订阅</strong>：</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>重置后<strong>旧链接立刻失效</strong>，所有设备需要用新链接重新导入。</p></div><h2 id="安全提醒" tabindex="-1">安全提醒 <a class="header-anchor" href="#安全提醒" aria-label="Permalink to &quot;安全提醒&quot;">​</a></h2><ul><li>订阅链接等同于你的账号使用权，<strong>不要分享给他人</strong>，不要发到群聊、论坛、截图中</li><li>多人使用会触发设备数限制，导致你自己无法连接</li><li>想邀请朋友使用，请用<a href="https://freedomport.cc/#/invite" target="_blank" rel="noreferrer">会员中心的邀请链接</a>，你还能拿佣金</li></ul><h2 id="常见疑问" tabindex="-1">常见疑问 <a class="header-anchor" href="#常见疑问" aria-label="Permalink to &quot;常见疑问&quot;">​</a></h2><p><strong>Q：订阅链接会变吗？</strong> A：不会主动变。只有你手动&quot;重置订阅&quot;后才会更换。续费、换套餐都不影响链接。</p><p><strong>Q：一条链接可以几台设备用？</strong> A：链接本身通用，同时在线设备数以套餐说明为准。</p><p><strong>Q：客户端提示订阅无效 / 拉取失败？</strong> A：先确认套餐未过期、流量未用完；再检查链接是否复制完整；仍失败请看 <a href="./faq">FAQ</a> 或<a href="https://freedomport.cc/#/ticket" target="_blank" rel="noreferrer">提交工单</a>。</p>',18)])])}const g=r(s,[["render",n]]);export{u as __pageData,g as default};
